use ckb_std::ckb_constants::Source;
use ckb_std::high_level::load_cell_data;
use ckb_std::error::SysError;

fn b2b256(parts: &[&[u8]]) -> Vec<u8> {
    let mut h = blake2b_ref::Blake2bBuilder::new(32).build();
    for p in parts { h.update(p); } let mut o=[0u8;32]; h.finalize(&mut o); o.to_vec()
}
fn ev_le(msgp: &[u8], index: u64, sigma: &[u8]) -> [u8;64] {
    let mut h = blake2b_ref::Blake2bBuilder::new(64).build();
    h.update(b"map"); h.update(msgp); h.update(&index.to_le_bytes()); h.update(sigma);
    let mut o=[0u8;64]; h.finalize(&mut o); o
}
const SHIFT: u32 = 768;
fn compute_target(stake: u64) -> BigInt {
    let s = BigInt::from(1u8) << SHIFT;
    let xa = BigInt::from(stake) * BigInt::from(C_NUM);
    let xb = BigInt::from(TOTAL) * BigInt::from(C_DEN);
    let mut t = s.clone(); let mut acc = s.clone(); let mut n: u64 = 0;
    loop { n += 1; t = &t * &xa; t = &t / &xb; t = &t / &BigInt::from(n);
        if t == BigInt::from(0u8) { break; } acc += &t; if n > 400 { break; } }
    let e512 = &acc >> (SHIFT - 512);
    (BigInt::from(1u8) << 512) - e512
}
fn ev_won(ev: [u8;64], target: &BigInt) -> bool { BigInt::from_bytes_le(Sign::Plus, &ev) < *target }
fn hexlow(b:&[u8])->Vec<u8>{ let h=b"0123456789abcdef"; let mut o=vec![0u8;b.len()*2]; for(i,&x)in b.iter().enumerate(){o[2*i]=h[(x>>4)as usize];o[2*i+1]=h[(x&0xf)as usize];} o }

fn check_m1() -> bool {
    let mut h = Sha256::new();
    for (k,v) in PARTS { sha2::Digest::update(&mut h, k); sha2::Digest::update(&mut h, v); }
    let d = h.finalize();
    if hexlow(&d).as_slice() != SM_ASCII { return false; }
    PARTS[0].1 == hexlow(TX_ROOT).as_slice()
}
fn check_bls(msgp: &[u8]) -> bool {
    let s0=G1Affine::from_compressed(&SIGMA0); let s1=G1Affine::from_compressed(&SIGMA1);
    let v0=G2Affine::from_compressed(&MVK0); let v1=G2Affine::from_compressed(&MVK1);
    if bool::from(s0.is_none()|s1.is_none()|v0.is_none()|v1.is_none()) { return false; }
    let agg_sig=G1Affine::from(G1Projective::from(s0.unwrap())+G1Projective::from(s1.unwrap()));
    let agg_mvk=G2Affine::from(G2Projective::from(v0.unwrap())+G2Projective::from(v1.unwrap()));
    let hm:G1Affine=<G1Projective as HashToCurve<ExpandMsgXmd<Sha256>>>::hash_to_curve(msgp,b"").into();
    pairing(&agg_sig,&G2Affine::generator()) == pairing(&hm,&agg_mvk)
}
fn check_lottery(msgp: &[u8]) -> bool {
    let t0 = compute_target(STAKE0); let t1 = compute_target(STAKE1);
    let mut count=0usize;
    for &i in IDX0 { if !ev_won(ev_le(msgp,i,&SIGMA0), &t0) { return false; } count+=1; }
    for &i in IDX1 { if !ev_won(ev_le(msgp,i,&SIGMA1), &t1) { return false; } count+=1; }
    count >= K
}
fn check_merkle_against(avk_root: &[u8;32]) -> bool {
    let l0 = b2b256(&[&MVK0, &STAKE0.to_be_bytes()]);
    let l1 = b2b256(&[&MVK1, &STAKE1.to_be_bytes()]);
    let root = b2b256(&[&b2b256(&[&l0,&l1]), &BVAL]);
    root.as_slice() == &avk_root[..]
}
#[cfg(feature="standalone")]
fn avk_root_src() -> Option<[u8;32]> { Some(AVK_ROOT) }
// SEC A8: the AVK may ONLY be read from an AUTHENTICATED AdvanceCert checkpoint cell (type-hash pinned),
// mirroring cert-verify's ADV_TYPEHASH check. Without this, ANY 48-byte cell-dep (an attacker-chosen avk)
// was accepted -> a forged committee -> a forged tx-set root.
const ADV_TYPEHASH: [u8;32] = [89,239,217,157,130,172,73,119,149,148,206,127,155,153,212,239,94,81,207,233,246,199,200,7,179,166,122,178,120,105,21,91];
#[cfg(not(feature="standalone"))]
fn avk_root_src() -> Option<[u8;32]> {
    use ckb_std::high_level::load_cell_type_hash;
    let mut i = 0usize;
    loop {
        match load_cell_data(i, Source::CellDep) {
            Ok(d) => {
                if d.len()==48 {
                    if let Ok(Some(th))=load_cell_type_hash(i, Source::CellDep) {
                        if th==ADV_TYPEHASH { let mut r=[0u8;32]; r.copy_from_slice(&d[8..40]); return Some(r); }
                    }
                }
                i+=1;
            }
            Err(SysError::IndexOutOfBound) => return None,
            Err(_) => return None,
        }
    }
}
// NOTE: SUPERSEDED prototype. The live verifier is ../../cert-verify/src/main.rs (deploy mode). The singleton
// guard below mirrors the tested cert-verify fix so a revival is not silently vulnerable.
fn program_entry() -> i8 {
    // SEC (singleton, RQ-SG): forbid a forged sibling LCKP riding this trusted type in the same group;
    // downstream consumers trust an LCKP cell by its type-hash, so an unvalidated sibling is a forged snapshot.
    if load_cell_data(1, Source::GroupInput).is_ok() { return 44; }
    if load_cell_data(1, Source::GroupOutput).is_ok() { return 45; }
    let avk_root = match avk_root_src() { Some(r) => r, None => return 1 };
    let mut msgp: Vec<u8> = SM_ASCII.to_vec(); msgp.extend_from_slice(&avk_root);
    if !check_m1() { return 10; }
    if !check_bls(&msgp) { return 11; }
    if !check_lottery(&msgp) { return 12; }
    if !check_merkle_against(&avk_root) { return 13; }
    // publish exactly LCKP || tx_root in this (output) checkpoint cell
    match load_cell_data(0, Source::GroupOutput) {
        Ok(out) => if out.len()==36 && &out[0..4]==b"LCKP" && &out[4..36]==TX_ROOT { 0 } else { 5 },
        Err(_) => 4,
    }
}
